async function getPokeData() {
  console.log("1. Sending request to server...");

  // Wait patiently for the internet connection to return
  let response = await fetch("https://pokeapi.co/api/v2/pokemon/ditto");

  // Wait patiently for the data to unpackage correctly
  let pokeData = await response.json();

  console.log("3. Acquired! Pokemon is: " + pokeData.name);
}

getPokeData();
console.log("2. This prints immediately because getPokeData is hiding in the background lane!");
